// node_conv_200 -- tiled-streaming 3x3 conv2d.
//   IC=64, OC=64, IH=IW=56, stride=1, padding=1, MP=4.
//   channel_tile=32 -> IN_BEATS=2, OUT_BEATS=2 per pixel.
//
// Split-architecture (coord_scheduler + line_buf_window + conv_datapath)
// wrapped with a beat-aggregator + beat-splitter. The library sees its
// valid_in combinationally on the wrapper's beat-1 cycle (fast path).
//
// Surgeon note (latency impasse, +56 cycle per-vector gap):
//   The library expects 1 valid_in per cycle for its fill phase, but a
//   tiled-streaming wrapper can only deliver one assembled pixel per
//   IN_BEATS (=2) wrapper cycles. The library's scheduler therefore only
//   advances every other wrapper cycle during fill, doubling the
//   ~57-cycle fill phase. The Python latency formula (37020 base, 37021
//   expected) was derived assuming a 1-pixel-per-cycle feed, so the
//   wrapper unavoidably overruns by ~ fill_cycles per vector. Fixing this
//   needs a tile-cadence MAC in the library, not a wrapper change.
//
// Compared to the prior Foundry attempt this version:
//   - collapses start_pulse + pending_rearm into a 3-state mini-FSM,
//   - removes the pixel_high_valid_r slow-path buffer (TB backpressure
//     via ready_in handles MAC stalls instead).

module node_conv_200 (
    input  wire                       clk,
    input  wire                       rst_n,
    input  wire                       valid_in,
    output wire                       ready_in,
    input  wire [255:0]               data_in,
    output wire                       valid_out,
    output wire [255:0]               data_out
);
    localparam integer IC             = 64;
    localparam integer OC             = 64;
    localparam integer IH             = 56;
    localparam integer IW             = 56;
    localparam integer OH             = 56;
    localparam integer OW             = 56;
    localparam integer KH             = 3;
    localparam integer KW             = 3;
    localparam integer SH             = 1;
    localparam integer SW             = 1;
    localparam integer PH             = 1;
    localparam integer PW             = 1;
    localparam integer K_TOTAL        = IC * KH * KW;
    localparam integer MP             = 4;

    localparam integer SCALE_MULT     = 23777;
    localparam integer SCALE_SHIFT    = 21;

    localparam integer CHANNEL_TILE   = 32;
    localparam integer TILE_BITS      = CHANNEL_TILE * 8;   // 256
    localparam integer IN_PIXEL_BITS  = IC * 8;             // 512
    localparam integer OUT_PIXEL_BITS = OC * 8;             // 512

    wire                                sched_needs_real_input;
    wire                                sched_ready_in;
    wire                                sched_output_fires;
    wire                                sched_advance;
    wire [$clog2(IH + PH + 1)-1:0]      sched_in_row;
    wire [$clog2(IW + PW + 1)-1:0]      sched_in_col;
    wire [$clog2(OH * OW + 1)-1:0]      sched_outputs_emitted;
    wire                                sched_out_frame_done;

    wire [KH*KW*IC*8-1:0]               window_flat;
    wire                                mac_busy;
    wire                                lib_valid_out_w;
    wire [OUT_PIXEL_BITS-1:0]           lib_data_out_w;

    localparam ST_ARM  = 2'd0;
    localparam ST_RUN  = 2'd1;
    localparam ST_WAIT = 2'd2;

    reg [1:0] frame_state;
    reg       start_pulse;

    reg                                 in_beat_idx;
    reg  [TILE_BITS-1:0]                pixel_low_r;

    wire                                beat0_now;
    wire                                beat1_now;

    assign ready_in  = (in_beat_idx == 1'b0) ? 1'b1 : sched_ready_in;
    assign beat0_now = valid_in && (in_beat_idx == 1'b0);
    assign beat1_now = valid_in && (in_beat_idx == 1'b1) && sched_ready_in;

    wire                                lib_valid_in_w = beat1_now;
    wire [IN_PIXEL_BITS-1:0]            lib_data_in_w  = {data_in, pixel_low_r};

    reg                                 out_beat1_pending_r;
    reg  [TILE_BITS-1:0]                out_pixel_high_r;

    assign valid_out = lib_valid_out_w || out_beat1_pending_r;
    assign data_out  = out_beat1_pending_r ? out_pixel_high_r
                                           : lib_data_out_w[TILE_BITS-1:0];

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            frame_state         <= ST_ARM;
            start_pulse         <= 1'b0;
            in_beat_idx         <= 1'b0;
            pixel_low_r         <= {TILE_BITS{1'b0}};
            out_beat1_pending_r <= 1'b0;
            out_pixel_high_r    <= {TILE_BITS{1'b0}};
        end else begin
            start_pulse <= 1'b0;

            case (frame_state)
                ST_ARM: begin
                    start_pulse <= 1'b1;
                    frame_state <= ST_RUN;
                end
                ST_RUN: begin
                    if (sched_out_frame_done) frame_state <= ST_WAIT;
                end
                ST_WAIT: begin
                    if (!mac_busy) frame_state <= ST_ARM;
                end
                default: frame_state <= ST_ARM;
            endcase

            if (beat0_now) begin
                pixel_low_r <= data_in;
                in_beat_idx <= 1'b1;
            end else if (beat1_now) begin
                in_beat_idx <= 1'b0;
            end

            if (lib_valid_out_w) begin
                out_pixel_high_r    <= lib_data_out_w[OUT_PIXEL_BITS-1:TILE_BITS];
                out_beat1_pending_r <= 1'b1;
            end else if (out_beat1_pending_r) begin
                out_beat1_pending_r <= 1'b0;
            end
        end
    end

    wire stall_in = mac_busy;

    coord_scheduler #(
        .IH(IH), .IW(IW), .OH(OH), .OW(OW),
        .KH(KH), .KW(KW), .SH(SH), .SW(SW),
        .PH(PH), .PW(PW)
    ) scheduler (
        .clk(clk), .rst_n(rst_n),
        .start(start_pulse),
        .stall_in(stall_in),
        .valid_in(lib_valid_in_w),
        .ready_in(sched_ready_in),
        .needs_real_input(sched_needs_real_input),
        .in_row(sched_in_row),
        .in_col(sched_in_col),
        .output_fires(sched_output_fires),
        .advance(sched_advance),
        .in_frame_done(),
        .out_frame_done(sched_out_frame_done),
        .outputs_emitted(sched_outputs_emitted)
    );

    line_buf_window #(
        .IC(IC), .IW(IW), .IH(IH),
        .KH(KH), .KW(KW), .PW(PW), .PH(PH)
    ) lbw (
        .clk(clk), .rst_n(rst_n),
        .frame_start(start_pulse),
        .sched_in_row(sched_in_row),
        .sched_in_col(sched_in_col),
        .sched_needs_real_input(sched_needs_real_input),
        .sched_advance(sched_advance),
        .sched_output_fires(sched_output_fires),
        .valid_in(lib_valid_in_w),
        .data_in(lib_data_in_w),
        .window_flat(window_flat)
    );

    conv_datapath #(
        .IC(IC), .OC(OC), .KH(KH), .KW(KW),
        .K_TOTAL(K_TOTAL), .MP(MP),
        .SCALE_MULT(SCALE_MULT), .SCALE_SHIFT(SCALE_SHIFT),
        .WEIGHTS_PATH("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_200_weights.hex"),
        .BIAS_PATH("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_200_bias.hex")
    ) dp (
        .clk(clk), .rst_n(rst_n),
        .window_flat(window_flat),
        .start_mac(sched_output_fires),
        .valid_out(lib_valid_out_w),
        .data_out(lib_data_out_w),
        .mac_busy(mac_busy)
    );

endmodule
